mapper.select:
select count(1)
from jst_enroll_record
where contest_id = #{contestId}
  and participant_id = #{participantId}
  and user_id = #{userId}
  and audit_status in ('pending', 'supplement')
  and del_flag = '0'

      and enroll_id <> #{excludeEnrollId}


select er.enroll_id, er.enroll_no, er.contest_id, c.contest_name, c.partner_id, er.participant_id,
       p.name as participant_name, p.guardian_mobile, er.material_status, er.audit_status,
       er.submit_time, er.update_time,
       ch.channel_id as bound_channel_id,
       ch.channel_name as bound_channel_name
from jst_enroll_record er
         left join jst_contest c on c.contest_id = er.contest_id and c.del_flag = '0'
         left join jst_participant p on p.participant_id = er.participant_id and p.del_flag = '0'
         left join jst_user u on u.user_id = er.user_id and u.del_flag = '0'
         left join jst_channel ch on ch.channel_id = coalesce(u.bound_channel_id, p.created_by_channel_id)
                                  and ch.del_flag = '0'

    er.del_flag = '0'

        and c.partner_id = #{query.partnerId}


        and er.contest_id = #{query.contestId}


        and er.contest_id in

            #{contestId}



        and er.audit_status = #{query.auditStatus}


        and er.material_status = #{query.materialStatus}


        and er.enroll_no = #{query.enrollNo}


        and p.name like concat('%', #{query.participantName}, '%')


        and p.guardian_mobile like concat('%', #{query.guardianMobile}, '%')



        and coalesce(u.bound_channel_id, p.created_by_channel_id) = #{query.boundChannelId}





                and coalesce(u.bound_channel_id, p.created_by_channel_id) is not null


                and coalesce(u.bound_channel_id, p.created_by_channel_id) is null




        ${query.params.dataScope}


order by er.update_time desc, er.enroll_id desc

select er.enroll_id, er.enroll_no, er.contest_id, c.contest_name, c.partner_id, er.participant_id, p.name as participant_name, p.guardian_mobile, er.material_status, er.audit_status, er.submit_time, er.update_time from jst_enroll_record er left join jst_contest c on c.contest_id = er.contest_id and c.del_flag = '0' left join jst_participant p on p.participant_id = er.participant_id and p.del_flag = '0' where er.del_flag = '0' and er.user_id = #{userId}
and er.audit_status = #{auditStatus}
order by er.update_time desc, er.enroll_id desc

mapper.update:
update jst_enroll_record
set audit_status = #{targetAuditStatus},

        material_status = #{materialStatus},

    audit_remark = #{auditRemark},
    update_by = #{updateBy},
    update_time = #{updateTime}
where enroll_id = #{enrollId}
  and audit_status = #{expectedAuditStatus}
  and del_flag = '0'
